import java.lang.String;
  import sailpoint.object.Identity;
if (accountGroup != null ) {
    String entName = accountGroup.getAttribute("name");
    log.trace("Entitlement name is : "+entName);
    if (entName != null && entName.startsWith("gcp-tp-data-datalake")) {
     
        Identity idn = context.getObjectByName(Identity.class, "Datalake Group Owners");
        Identity workgroup = context.getObjectByName(Identity.class, "Third Level datalake approvers");
        String L2App = workgroup.getId();
        accountGroup.setOwner(idn);
        accountGroup.setAttribute("approvalType","manager,owner,identity");
        accountGroup.setAttribute("additionalApprover",L2App);
        accountGroup.setRequestable(true);
        return accountGroup;
        } else {
         accountGroup.setRequestable(false); 
    }
        
return accountGroup;
}
